def pricing_plugin(price: float) -> str:
    return f"Final price: ${price}"

# Register plugin
plugin = kernel.import_function(pricing_plugin, plugin_name="Pricing")

# Add Vex filter
@kernel.register_function()
def validate_pricing_with_vex(*, price: float) -> str:
    result = pricing_plugin(price)
    report = vex.validate({
        "output": result,
        "policy": "ecommerce_pricing_accuracy",
        "context": {"product_id": "123"}
    })
    if report.passed:
        return result
    raise ValueError(f"Pricing validation failed: {report.reason}")

import { Kernel } from '@semantic-kernel/core';
import { VexClient } from 'vex-sdk';

const kernel = new Kernel();
const vex = new VexClient({ apiKey: 'your-vex-key' });

// E-commerce planner function
async function createShoppingPlan(query: string) {
  const planner = kernel.getService('planner');
  const plan = await planner.createPlan({
    goals: [{ instruction: `Handle e-commerce query: ${query}` }]
  });

  // Vex validation
  const report = await vex.validate({
    output: plan.toJson(),
    policy: 'ecommerce_plan_validity',
    context: { query }
  });

  if (!report.passed) {
    throw new Error(`Invalid plan: ${report.reason}`);
  }

  return plan;
}
